1	/**
2	 * Mixer audio graph engine.
3	 * Per-track channel strips -> master bus -> brickwall limiter -> destination.
4	 *
5	 * INV-2: Non-bypassable DynamicsCompressorNode as brickwall limiter
6	 * (threshold=-1dBFS, ratio=20:1, knee=0, attack=0.001s)
7	 */
8	
9	import type { ChannelStrip, MasterBus, MixerEngine } from "./types";
10	import { createInsertChain, type InsertChain } from "./insert-chain";
11	
12	function clamp(v: number, min: number, max: number): number {
13	  return Math.min(max, Math.max(min, v));
14	}
15	
16	/**
17	 * Quadratic fader taper: attempt to model a real mixing console fader.
18	 * Maps linear 0..2 -> gain curve.
19	 * 0 -> 0 (silence), 1 -> 1 (unity), 2 -> 2 (boost)
20	 */
21	function faderTaper(linear: number): number {
22	  if (linear <= 0) return 0;
23	  if (linear <= 1) {
24	    // Attempt log curve: x^2 gives reasonable taper for 0..1
25	    return linear * linear;
26	  }
27	  // Above unity: linear interpolation from 1..2
28	  return 1 + (linear - 1);
29	}
30	
31	function createMasterBus(ctx: AudioContext): MasterBus {
32	  const inputGain = ctx.createGain();
33	  const faderGain = ctx.createGain();
34	  const limiter = ctx.createDynamicsCompressor();
35	  const analyser = ctx.createAnalyser();
36	
37	  // INV-2: Brickwall limiter settings
38	  limiter.threshold.value = -1;
39	  limiter.ratio.value = 20;
40	  limiter.knee.value = 0;
41	  limiter.attack.value = 0.001;
42	  limiter.release.value = 0.01;
43	
44	  // Chain: inputGain -> faderGain -> limiter -> analyser -> destination
45	  inputGain.connect(faderGain);
46	  faderGain.connect(limiter);
47	  limiter.connect(analyser);
48	  analyser.connect(ctx.destination);
49	
50	  return { inputGain, faderGain, limiter, analyser };
51	}
52	
53	function createChannelStrip(
54	  ctx: AudioContext,
55	  trackId: string,
56	  masterInput: GainNode,
57	): ChannelStrip {
58	  const inputGain = ctx.createGain();
59	  const faderGain = ctx.createGain();
60	  const panner = ctx.createStereoPanner();
61	  const muteGain = ctx.createGain();
62	  const analyser = ctx.createAnalyser();
63	
64	  // Chain: inputGain -> [insert chain] -> faderGain -> panner -> muteGain -> analyser -> master input
65	  // Note: inputGain -> faderGain connection is managed by the insert chain
66	  faderGain.connect(panner);
67	  panner.connect(muteGain);
68	  muteGain.connect(analyser);
69	  analyser.connect(masterInput);
70	
71	  return {
72	    trackId,
73	    inputGain,
74	    inserts: [],
75	    faderGain,
76	    panner,
77	    muteGain,
78	    analyser,
79	    muted: false,
80	    solo: false,
81	    soloIsolate: false,
82	  };
83	}
84	
85	export function createMixerEngine(ctx: AudioContext): MixerEngine {
86	  const master = createMasterBus(ctx);
87	  const strips = new Map<string, ChannelStrip>();
88	  const insertChains = new Map<string, InsertChain>();
89	  let savedMasterLevel = 1;
90	
91	  function applyMuteState(strip: ChannelStrip): void {
92	    const hasSolo = [...strips.values()].some((s) => s.solo);
93	
94	    if (strip.muted) {
95	      strip.muteGain.gain.value = 0;
96	      return;
97	    }
98	
99	    if (hasSolo) {
100	      if (strip.solo || strip.soloIsolate) {
101	        strip.muteGain.gain.value = 1;
102	      } else {
103	        strip.muteGain.gain.value = 0;
104	      }
105	    } else {
106	      strip.muteGain.gain.value = 1;
107	    }
108	  }
109	
110	  const engine: MixerEngine = {
111	    getOrCreateStrip(trackId: string): ChannelStrip {
112	      const existing = strips.get(trackId);
113	      if (existing) return existing;
114	
115	      const strip = createChannelStrip(ctx, trackId, master.inputGain);
116	      strips.set(trackId, strip);
117	      // Insert chain between inputGain and faderGain
118	      const chain = createInsertChain(strip.inputGain, strip.faderGain);
119	      insertChains.set(trackId, chain);
120	      return strip;
121	    },
122	
123	    removeStrip(trackId: string): void {
124	      const strip = strips.get(trackId);
125	      if (!strip) return;
126	
127	      const chain = insertChains.get(trackId);
128	      chain?.dispose();
129	      insertChains.delete(trackId);
130	
131	      strip.inputGain.disconnect();
132	      strip.faderGain.disconnect();
133	      strip.panner.disconnect();
134	      strip.muteGain.disconnect();
135	      strip.analyser.disconnect();
136	      strips.delete(trackId);
137	    },
138	
139	    getStrip(trackId: string): ChannelStrip | undefined {
140	      return strips.get(trackId);
141	    },
142	
143	    getAllStrips(): readonly ChannelStrip[] {
144	      return [...strips.values()];
145	    },
146	
147	    getMaster(): MasterBus {
148	      return master;
149	    },
150	
151	    setFaderLevel(trackId: string, level: number): void {
152	      const strip = strips.get(trackId);
153	      if (!strip) return;
154	      const clamped = clamp(level, 0, 2);
155	      strip.faderGain.gain.value = faderTaper(clamped);
156	    },
157	
158	    setPan(trackId: string, pan: number): void {
159	      const strip = strips.get(trackId);
160	      if (!strip) return;
161	      strip.panner.pan.value = clamp(pan, -1, 1);
162	    },
163	
164	    setMute(trackId: string, muted: boolean): void {
165	      const strip = strips.get(trackId);
166	      if (!strip) return;
167	      strip.muted = muted;
168	      applyMuteState(strip);
169	    },
170	
171	    setSolo(trackId: string, solo: boolean): void {
172	      const strip = strips.get(trackId);
173	      if (!strip) return;
174	      strip.solo = solo;
175	      engine.updateSoloState();
176	    },
177	
178	    setSoloIsolate(trackId: string, enabled: boolean): void {
179	      const strip = strips.get(trackId);
180	      if (!strip) return;
181	      strip.soloIsolate = enabled;
182	      engine.updateSoloState();
183	    },
184	
185	    updateSoloState(): void {
186	      for (const strip of strips.values()) {
187	        applyMuteState(strip);
188	      }
189	    },
190	
191	    setMasterLevel(level: number): void {
192	      savedMasterLevel = clamp(level, 0, 2);
193	      master.faderGain.gain.value = savedMasterLevel;
194	    },
195	
196	    getTrackInput(trackId: string): AudioNode {
197	      return engine.getOrCreateStrip(trackId).inputGain;
198	    },
199	
200	    addInsert(
201	      trackId: string,
202	      id: string,
203	      input: AudioNode,
204	      output: AudioNode,
205	    ): void {
206	      const chain = insertChains.get(trackId);
207	      chain?.addInsert(id, input, output);
208	    },
209	
210	    removeInsert(trackId: string, insertId: string): void {
211	      const chain = insertChains.get(trackId);
212	      chain?.removeInsert(insertId);
213	    },
214	
215	    emergencyMute(): void {
216	      master.faderGain.gain.value = 0;
217	    },
218	
219	    releaseEmergencyMute(): void {
220	      master.faderGain.gain.value = savedMasterLevel;
221	    },
222	
223	    dispose(): void {
224	      for (const chain of insertChains.values()) {
225	        chain.dispose();
226	      }
227	      insertChains.clear();
228	      for (const strip of strips.values()) {
229	        strip.inputGain.disconnect();
230	        strip.faderGain.disconnect();
231	        strip.panner.disconnect();
232	        strip.muteGain.disconnect();
233	        strip.analyser.disconnect();
234	      }
235	      strips.clear();
236	      master.inputGain.disconnect();
237	      master.faderGain.disconnect();
238	      master.limiter.disconnect();
239	      master.analyser.disconnect();
240	    },
241	  };
242	
243	  return engine;
244	}
