1	/**
2	 * Core types for the effects rack system.
3	 * Effect factory registry pattern: given type ID -> AudioNode chain + parameter schema.
4	 */
5	
6	import type { z } from "zod/v4";
7	
8	export type EffectParameterSchema = {
9	  readonly name: string;
10	  readonly key: string;
11	  readonly min: number;
12	  readonly max: number;
13	  readonly default: number;
14	  readonly step: number;
15	  readonly unit: string;
16	};
17	
18	export type EffectDefinition = {
19	  readonly id: string;
20	  readonly name: string;
21	  readonly parameters: readonly EffectParameterSchema[];
22	};
23	
24	export type EffectInstance = {
25	  readonly id: string;
26	  readonly typeId: string;
27	  readonly input: AudioNode;
28	  readonly output: AudioNode;
29	  readonly dryGain: GainNode;
30	  readonly wetGain: GainNode;
31	  bypassed: boolean;
32	  getParam(key: string): number;
33	  setParam(key: string, value: number): void;
34	  setBypassed(bypassed: boolean): void;
35	  setMix(wet: number): void;
36	  dispose(): void;
37	};
38	
39	export type EffectPreset = {
40	  readonly typeId: string;
41	  readonly name: string;
42	  readonly params: Record<string, number>;
43	};
44	
45	export type EffectFactory = {
46	  readonly definition: EffectDefinition;
47	  create(ctx: AudioContext, id: string): EffectInstance;
48	};
49	
50	export type EffectRegistry = {
51	  register(factory: EffectFactory): void;
52	  get(typeId: string): EffectFactory | undefined;
53	  getAll(): readonly EffectFactory[];
54	  create(typeId: string, ctx: AudioContext, id?: string): EffectInstance;
55	};
56	
57	/** Zod schema type for preset validation (runtime) */
58	export type EffectPresetSchema = z.ZodType<EffectPreset>;
