1	/**
2	 * Bridge between effects Zustand store and Web Audio instances.
3	 * Subscribes to store changes, creates/disposes EffectInstances,
4	 * and wires them into the MixerEngine's insert chains.
5	 */
6	
7	import type { EffectInstance, EffectRegistry } from "./types";
8	import type { MixerEngine } from "@audio/mixer";
9	import { useEffectsStore } from "@state/effects";
10	import type { EffectSlotState } from "@state/effects";
11	
12	export type EffectsBridge = {
13	  /** Get a live audio instance by effect ID */
14	  getInstance(effectId: string): EffectInstance | undefined;
15	  /** Tear down all instances and unsubscribe */
16	  dispose(): void;
17	};
18	
19	export function createEffectsBridge(
20	  ctx: AudioContext,
21	  registry: EffectRegistry,
22	  mixer: MixerEngine,
23	): EffectsBridge {
24	  const instances = new Map<string, EffectInstance>();
25	  const effectTrackMap = new Map<string, string>();
26	
27	  function syncSlot(trackId: string, slot: EffectSlotState): void {
28	    const existing = instances.get(slot.id);
29	    if (existing) {
30	      // Sync params
31	      for (const [key, value] of Object.entries(slot.params)) {
32	        if (existing.getParam(key) !== value) {
33	          existing.setParam(key, value);
34	        }
35	      }
36	      // Sync bypass
37	      if (existing.bypassed !== slot.bypassed) {
38	        existing.setBypassed(slot.bypassed);
39	      }
40	      return;
41	    }
42	
43	    // Create new instance via registry
44	    const instance = registry.create(slot.typeId, ctx, slot.id);
45	    instances.set(slot.id, instance);
46	    effectTrackMap.set(slot.id, trackId);
47	
48	    // Apply initial state
49	    for (const [key, value] of Object.entries(slot.params)) {
50	      instance.setParam(key, value);
51	    }
52	    instance.setBypassed(slot.bypassed);
53	
54	    // Ensure channel strip exists, then wire insert
55	    mixer.getOrCreateStrip(trackId);
56	    mixer.addInsert(trackId, slot.id, instance.input, instance.output);
57	  }
58	
59	  function removeInstance(effectId: string): void {
60	    const instance = instances.get(effectId);
61	    if (!instance) return;
62	
63	    const trackId = effectTrackMap.get(effectId);
64	    if (trackId !== undefined && trackId !== "") {
65	      mixer.removeInsert(trackId, effectId);
66	    }
67	
68	    instance.dispose();
69	    instances.delete(effectId);
70	    effectTrackMap.delete(effectId);
71	  }
72	
73	  function sync(): void {
74	    const state = useEffectsStore.getState();
75	    const activeIds = new Set<string>();
76	
77	    for (const [trackId, slots] of Object.entries(state.trackEffects)) {
78	      for (const slot of slots) {
79	        activeIds.add(slot.id);
80	        syncSlot(trackId, slot);
81	      }
82	    }
83	
84	    // Remove instances no longer in store
85	    for (const id of [...instances.keys()]) {
86	      if (!activeIds.has(id)) {
87	        removeInstance(id);
88	      }
89	    }
90	  }
91	
92	  // Initial sync
93	  sync();
94	
95	  // Subscribe to store changes
96	  const unsub = useEffectsStore.subscribe(sync);
97	
98	  return {
99	    getInstance(effectId) {
100	      return instances.get(effectId);
101	    },
102	    dispose() {
