1	/**
2	 * Base effect builder with wet/dry bypass infrastructure.
3	 * Every effect uses this to get consistent bypass, mix, and param management.
4	 */
5	
6	import type { EffectInstance, EffectParameterSchema } from "./types";
7	
8	function clamp(v: number, min: number, max: number): number {
9	  return Math.min(max, Math.max(min, v));
10	}
11	
12	export type ApplyParamFn = (
13	  key: string,
14	  value: number,
15	  setMix: (wet: number) => void,
16	) => void;
17	
18	export type CreateEffectOptions = {
19	  ctx: AudioContext;
20	  id: string;
21	  typeId: string;
22	  params: readonly EffectParameterSchema[];
23	  /** Wire internal effect nodes between inputNode and outputNode */
24	  buildChain(inputNode: GainNode, outputNode: GainNode): void;
25	  /** Called when a parameter changes. Use setMix callback for mix params. */
26	  applyParam: ApplyParamFn;
27	  /** Clean up internal effect nodes (stop oscillators, disconnect nodes) */
28	  disposeChain?: () => void;
29	};
30	
31	/**
32	 * Creates a base effect instance with:
33	 * - Wet/dry split: input -> dryGain -> output, input -> [effect chain] -> wetGain -> output
34	 * - Bypass toggle (sets dry=1, wet=0)
35	 * - Parameter storage with clamping
36	 */
37	export function createBaseEffect(opts: CreateEffectOptions): EffectInstance {
38	  const { ctx, id, typeId, params, applyParam } = opts;
39	
40	  const input = ctx.createGain();
41	  const output = ctx.createGain();
42	  const dryGain = ctx.createGain();
43	  const wetGain = ctx.createGain();
44	
45	  // Internal nodes for the effect chain
46	  const effectInput = ctx.createGain();
47	  const effectOutput = ctx.createGain();
48	
49	  // Dry path: input -> dryGain -> output
50	  input.connect(dryGain);
51	  dryGain.connect(output);
52	
53	  // Wet path: input -> effectInput -> [effect chain] -> effectOutput -> wetGain -> output
54	  input.connect(effectInput);
55	  opts.buildChain(effectInput, effectOutput);
56	  effectOutput.connect(wetGain);
57	  wetGain.connect(output);
58	
59	  // Default: fully wet (no dry signal)
60	  dryGain.gain.value = 0;
61	  wetGain.gain.value = 1;
62	
63	  // Parameter storage
64	  const paramMap = new Map<
65	    string,
66	    { schema: EffectParameterSchema; value: number }
67	  >();
68	  for (const p of params) {
69	    paramMap.set(p.key, { schema: p, value: p.default });
70	  }
71	
72	  let bypassed = false;
73	  let mixLevel = 1; // 0 = fully dry, 1 = fully wet
74	
75	  // 5ms ramp avoids audible clicks on gain changes
76	  const RAMP_TIME = 0.005;
77	
78	  function rampTo(param: AudioParam, value: number): void {
79	    if (typeof param.linearRampToValueAtTime === "function") {
80	      param.setValueAtTime(param.value, ctx.currentTime);
81	      param.linearRampToValueAtTime(value, ctx.currentTime + RAMP_TIME);
82	    } else {
83	      param.value = value;
84	    }
85	  }
86	
87	  function applyMix(): void {
88	    if (bypassed) {
89	      rampTo(dryGain.gain, 1);
90	      rampTo(wetGain.gain, 0);
91	    } else {
92	      rampTo(dryGain.gain, 1 - mixLevel);
93	      rampTo(wetGain.gain, mixLevel);
94	    }
95	  }
96	
97	  function setMix(wet: number): void {
98	    mixLevel = clamp(wet, 0, 1);
99	    applyMix();
100	  }
101	
102	  const instance: EffectInstance = {
103	    id,
104	    typeId,
105	    input,
106	    output,
107	    dryGain,
108	    wetGain,
109	    bypassed: false,
110	
111	    getParam(key: string): number {
112	      return paramMap.get(key)?.value ?? 0;
113	    },
114	
115	    setParam(key: string, value: number): void {
116	      const entry = paramMap.get(key);
117	      if (!entry) return;
118	      entry.value = clamp(value, entry.schema.min, entry.schema.max);
119	      applyParam(key, entry.value, setMix);
120	    },
121	
122	    setBypassed(b: boolean): void {
123	      bypassed = b;
124	      instance.bypassed = b;
125	      applyMix();
126	    },
127	
128	    setMix,
129	
130	    dispose(): void {
131	      opts.disposeChain?.();
132	      input.disconnect();
133	      output.disconnect();
134	      dryGain.disconnect();
135	      wetGain.disconnect();
136	      effectInput.disconnect();
137	      effectOutput.disconnect();
138	    },
139	  };
140	
141	  // Initialize all params (deferred to after instance creation)
142	  for (const [key, entry] of paramMap) {
143	    applyParam(key, entry.value, setMix);
144	  }
145	
146	  return instance;
147	}
