39	function generateImpulseResponse(
40	  ctx: AudioContext,
41	  decaySeconds: number,
42	): AudioBuffer {
43	  const sampleRate = ctx.sampleRate;
44	  const length = Math.floor(sampleRate * decaySeconds);
