46	
47	  for (let ch = 0; ch < 2; ch++) {
48	    const data = buffer.getChannelData(ch);
49	    for (let i = 0; i < length; i++) {
50	      const t = i / sampleRate;
51	      // Exponential decay envelope * white noise
52	      data[i] = (Math.random() * 2 - 1) * Math.exp((-3 * t) / decaySeconds);
53	    }
54	  }
55	  return buffer;
56	}
