4	describe("DFS cycle detection (INV-1)", () => {
5	  it("empty graph has no cycle", () => {
6	    const graph = new RoutingGraph();
7	    expect(hasCycle(graph)).toBe(false);
8	  });
9	
10	  it("single node has no cycle", () => {
11	    const graph = new RoutingGraph();
12	    graph.addNode("a");
13	    expect(hasCycle(graph)).toBe(false);
14	  });
15	
16	  it("linear chain has no cycle", () => {
17	    const graph = new RoutingGraph();
18	    graph.addNode("a");
19	    graph.addNode("b");
20	    graph.addNode("c");
21	    graph.addEdge("a", "b");
22	    graph.addEdge("b", "c");
23	    expect(hasCycle(graph)).toBe(false);
24	  });
25	
26	  it("detects simple cycle", () => {
27	    const graph = new RoutingGraph();
28	    graph.addNode("a");
29	    graph.addNode("b");
30	    graph.addEdge("a", "b");
31	    graph.addEdge("b", "a");
32	    expect(hasCycle(graph)).toBe(true);
33	  });
34	
35	  it("detects cycle in larger graph", () => {
36	    const graph = new RoutingGraph();
37	    graph.addNode("a");
38	    graph.addNode("b");
39	    graph.addNode("c");
40	    graph.addNode("d");
41	    graph.addEdge("a", "b");
42	    graph.addEdge("b", "c");
43	    graph.addEdge("c", "d");
44	    graph.addEdge("d", "b"); // cycle: b -> c -> d -> b
45	    expect(hasCycle(graph)).toBe(true);
46	  });
47	
48	  it("self-loop is a cycle", () => {
49	    const graph = new RoutingGraph();
50	    graph.addNode("a");
51	    graph.addEdge("a", "a");
52	    expect(hasCycle(graph)).toBe(true);
53	  });
54	
55	  it("wouldCauseCycle checks hypothetical edge", () => {
56	    const graph = new RoutingGraph();
57	    graph.addNode("a");
58	    graph.addNode("b");
59	    graph.addNode("c");
60	    graph.addEdge("a", "b");
61	    graph.addEdge("b", "c");
62	
63	    // Adding c -> a would create cycle
64	    expect(graph.wouldCauseCycle("c", "a")).toBe(true);
65	    // Adding a -> c would not (already path a->b->c)
66	    expect(graph.wouldCauseCycle("a", "c")).toBe(false);
67	  });
68	
69	  it("removeEdge breaks cycle", () => {
70	    const graph = new RoutingGraph();
71	    graph.addNode("a");
72	    graph.addNode("b");
73	    graph.addEdge("a", "b");
74	    graph.addEdge("b", "a");
75	    expect(hasCycle(graph)).toBe(true);
76	
77	    graph.removeEdge("b", "a");
78	    expect(hasCycle(graph)).toBe(false);
79	  });
