1	/**
2	 * Mixer audio graph engine.
3	 * Per-track channel strips -> master bus -> brickwall limiter -> destination.
4	 *
5	 * INV-2: Non-bypassable DynamicsCompressorNode as brickwall limiter
6	 * (threshold=-1dBFS, ratio=20:1, knee=0, attack=0.001s)
7	 */
8	
9	import type { ChannelStrip, MasterBus, MixerEngine } from "./types";
10	import { createInsertChain, type InsertChain } from "./insert-chain";
11	
12	function clamp(v: number, min: number, max: number): number {
13	  return Math.min(max, Math.max(min, v));
14	}
15	
16	/**
17	 * Quadratic fader taper: attempt to model a real mixing console fader.
18	 * Maps linear 0..2 -> gain curve.
19	 * 0 -> 0 (silence), 1 -> 1 (unity), 2 -> 2 (boost)
20	 */
21	function faderTaper(linear: number): number {
22	  if (linear <= 0) return 0;
23	  if (linear <= 1) {
24	    // Attempt log curve: x^2 gives reasonable taper for 0..1
25	    return linear * linear;
26	  }
27	  // Above unity: linear interpolation from 1..2
28	  return 1 + (linear - 1);
29	}
30	
31	function createMasterBus(ctx: AudioContext): MasterBus {
32	  const inputGain = ctx.createGain();
33	  const faderGain = ctx.createGain();
34	  const limiter = ctx.createDynamicsCompressor();
35	  const analyser = ctx.createAnalyser();
36	
37	  // INV-2: Brickwall limiter settings
38	  limiter.threshold.value = -1;
39	  limiter.ratio.value = 20;
40	  limiter.knee.value = 0;
41	  limiter.attack.value = 0.001;
42	  limiter.release.value = 0.01;
43	
44	  // Chain: inputGain -> faderGain -> limiter -> analyser -> destination
45	  inputGain.connect(faderGain);
46	  faderGain.connect(limiter);
47	  limiter.connect(analyser);
48	  analyser.connect(ctx.destination);
49	
50	  return { inputGain, faderGain, limiter, analyser };
51	}
52	
53	function createChannelStrip(
54	  ctx: AudioContext,
55	  trackId: string,
56	  masterInput: GainNode,
57	): ChannelStrip {
58	  const inputGain = ctx.createGain();
59	  const faderGain = ctx.createGain();
60	  const panner = ctx.createStereoPanner();
61	  const muteGain = ctx.createGain();
62	  const analyser = ctx.createAnalyser();
63	
64	  // Chain: inputGain -> [insert chain] -> faderGain -> panner -> muteGain -> analyser -> master input
65	  // Note: inputGain -> faderGain connection is managed by the insert chain
66	  faderGain.connect(panner);
67	  panner.connect(muteGain);
68	  muteGain.connect(analyser);
69	  analyser.connect(masterInput);
70	
71	  return {
72	    trackId,
73	    inputGain,
74	    inserts: [],
75	    faderGain,
76	    panner,
77	    muteGain,
78	    analyser,
79	    muted: false,
80	    solo: false,
81	    soloIsolate: false,
82	  };
83	}
84	
85	export function createMixerEngine(ctx: AudioContext): MixerEngine {
86	  const master = createMasterBus(ctx);
87	  const strips = new Map<string, ChannelStrip>();
88	  const insertChains = new Map<string, InsertChain>();
89	  let savedMasterLevel = 1;
