1	import { describe, it, expect, beforeEach, vi } from "vitest";
2	import { createMixerEngine } from "./mixer-engine";
3	import type { MixerEngine } from "./types";
4	
5	type MockNode = {
6	  gain: {
7	    value: number;
8	    setValueAtTime: ReturnType<typeof vi.fn>;
9	    linearRampToValueAtTime: ReturnType<typeof vi.fn>;
10	  };
11	  connect: ReturnType<typeof vi.fn>;
12	  disconnect: ReturnType<typeof vi.fn>;
13	};
14	
15	function asMock(node: AudioNode): MockNode {
16	  return node as unknown as MockNode;
17	}
18	
19	function createMockAudioContext(): AudioContext {
20	  const mockGainNode = (): MockNode => ({
21	    gain: {
22	      value: 1,
23	      setValueAtTime: vi.fn(),
24	      linearRampToValueAtTime: vi.fn(),
25	    },
26	    connect: vi.fn().mockReturnThis(),
27	    disconnect: vi.fn(),
28	  });
29	
30	  const mockAnalyser = (): MockNode => ({
31	    ...mockGainNode(),
32	    ...{
33	      fftSize: 2048,
34	      frequencyBinCount: 1024,
35	      smoothingTimeConstant: 0.8,
36	      getFloatTimeDomainData: vi.fn(),
37	      getByteTimeDomainData: vi.fn(),
38	    },
39	  });
40	
41	  const mockPanner = (): object => ({
42	    pan: { value: 0, setValueAtTime: vi.fn() },
43	    connect: vi.fn().mockReturnThis(),
44	    disconnect: vi.fn(),
45	  });
46	
47	  const mockCompressor = (): object => ({
48	    threshold: { value: -24, setValueAtTime: vi.fn() },
49	    ratio: { value: 12, setValueAtTime: vi.fn() },
50	    knee: { value: 30, setValueAtTime: vi.fn() },
51	    attack: { value: 0.003, setValueAtTime: vi.fn() },
52	    release: { value: 0.25, setValueAtTime: vi.fn() },
53	    connect: vi.fn().mockReturnThis(),
54	    disconnect: vi.fn(),
55	  });
56	
57	  return {
58	    createGain: vi.fn().mockImplementation(mockGainNode),
59	    createAnalyser: vi.fn().mockImplementation(mockAnalyser),
60	    createStereoPanner: vi.fn().mockImplementation(mockPanner),
61	    createDynamicsCompressor: vi.fn().mockImplementation(mockCompressor),
62	    destination: { connect: vi.fn(), disconnect: vi.fn() },
63	    currentTime: 0,
64	    sampleRate: 44100,
65	  } as unknown as AudioContext;
66	}
67	
68	describe("MixerEngine", () => {
69	  let ctx: AudioContext;
70	  let mixer: MixerEngine;
71	
72	  beforeEach(() => {
73	    ctx = createMockAudioContext();
74	    mixer = createMixerEngine(ctx);
75	  });
76	
77	  describe("master bus", () => {
78	    it("creates master bus with limiter", () => {
79	      const master = mixer.getMaster();
80	      expect(master.inputGain).toBeDefined();
81	      expect(master.faderGain).toBeDefined();
82	      expect(master.limiter).toBeDefined();
83	      expect(master.analyser).toBeDefined();
84	    });
85	
86	    it("sets limiter to brickwall settings (INV-2)", () => {
87	      const master = mixer.getMaster();
88	      const limiter = master.limiter;
89	      expect(limiter.threshold.value).toBe(-1);
90	      expect(limiter.ratio.value).toBe(20);
91	      expect(limiter.knee.value).toBe(0);
92	      expect(limiter.attack.value).toBeCloseTo(0.001, 3);
93	    });
94	
95	    it("connects master chain: inputGain -> faderGain -> limiter -> analyser -> destination", () => {
96	      const master = mixer.getMaster();
97	      expect(asMock(master.inputGain).connect).toHaveBeenCalledWith(
98	        master.faderGain,
99	      );
100	      expect(asMock(master.faderGain).connect).toHaveBeenCalledWith(
101	        master.limiter,
102	      );
103	      expect(asMock(master.limiter).connect).toHaveBeenCalledWith(
104	        master.analyser,
105	      );
106	      expect(asMock(master.analyser).connect).toHaveBeenCalledWith(
107	        ctx.destination,
108	      );
109	    });
110	
111	    it("sets master fader level", () => {
112	      mixer.setMasterLevel(0.5);
113	      const master = mixer.getMaster();
114	      expect(master.faderGain.gain.value).toBeCloseTo(0.5);
115	    });
116	  });
117	
118	  describe("channel strips", () => {
119	    it("creates a channel strip for a track", () => {
120	      const strip = mixer.getOrCreateStrip("track-1");
121	      expect(strip.trackId).toBe("track-1");
