190	  describe("pan", () => {
191	    it("sets pan value", () => {
192	      mixer.getOrCreateStrip("track-1");
193	      mixer.setPan("track-1", -0.5);
194	      expect(mixer.getStrip("track-1")?.panner.pan.value).toBeCloseTo(-0.5);
195	    });
196	
