/**
 * Tests for E13 routing state store.
 * Zustand store for sends, buses, and sidechain assignments.
 */

import { describe, it, expect, beforeEach } from "vitest";
import { useRoutingStore, type RoutingStore } from "./routing-store";
import type { SendState, BusState, SidechainState } from "./types";

describe("RoutingStore", () => {
  beforeEach(() => {
    useRoutingStore.setState({
      buses: {},
      sends: {},
      sidechains: [],
    });
  });

  describe("bus management", () => {
    it("adds a bus", () => {
      useRoutingStore.getState().addBus({ id: "bus-1", name: "Reverb Bus", outputTarget: "master" });
      const bus = useRoutingStore.getState().buses["bus-1"];
      expect(bus).toBeDefined();
      expect(bus?.name).toBe("Reverb Bus");
      expect(bus?.outputTarget).toBe("master");
    });

    it("removes a bus", () => {
      useRoutingStore.getState().addBus({ id: "bus-1", name: "Bus", outputTarget: "master" });
      useRoutingStore.getState().removeBus("bus-1");
      expect(useRoutingStore.getState().buses["bus-1"]).toBeUndefined();
    });

    it("removes sends to bus when bus is removed", () => {
      useRoutingStore.getState().addBus({ id: "bus-1", name: "Bus", outputTarget: "master" });
      useRoutingStore.getState().addSend("track-1", { busId: "bus-1", level: 0.5, preFader: false });
      useRoutingStore.getState().removeBus("bus-1");
      expect(useRoutingStore.getState().getSends("track-1")).toHaveLength(0);
    });

    it("updates bus output target", () => {
      useRoutingStore.getState().addBus({ id: "bus-1", name: "Bus 1", outputTarget: "master" });
      useRoutingStore.getState().addBus({ id: "bus-2", name: "Bus 2", outputTarget: "master" });
      useRoutingStore.getState().setBusOutput("bus-1", "bus-2");
      expect(useRoutingStore.getState().buses["bus-1"]?.outputTarget).toBe("bus-2");
    });
  });

  describe("send management", () => {
    it("adds a send to a track", () => {
      useRoutingStore.getState().addBus({ id: "bus-1", name: "Bus", outputTarget: "master" });
      useRoutingStore.getState().addSend("track-1", { busId: "bus-1", level: 0.7, preFader: false });
      const sends = useRoutingStore.getState().getSends("track-1");
      expect(sends).toHaveLength(1);
